class UnionFind {
    private val parent: MutableList<Int>
    private val rank: MutableList<Int>

    constructor(n: Int) {
        parent = MutableList(n) { it }
        rank = MutableList(n) { 1 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun unite(x: Int, y: Int) {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX != rootY) {
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX
            } else {
                parent[rootX] = rootY
                if (rank[rootX] == rank[rootY]) {
                    rank[rootY]++
                }
            }
        }
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    if (k == 1L) return 0L

    val maxTime = edges.map { it[2] }.maxOrNull() ?: 0L
    var low = 0L
    var high = maxTime
    var answer = high

    while (low <= high) {
        val mid = (low + high) / 2
        val count = n.toInt()
        val uf = UnionFind(n.toInt())
        for (edge in edges) {
            val time = edge[2]
            if (time > mid) {
                val u = edge[0].toInt()
                val v = edge[1].toInt()
                val rootU = uf.find(u)
                val rootV = uf.find(v)
                if (rootU != rootV) {
                    uf.unite(u, v)
                    count--
                }
            }
        }
        if (count >= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return answer
}
