fun countComponents(n: Long, edges: Array<Array<Long>>, t: Long): Int {
    val parent = LongArray(n.toInt())
    for (i in 0 until n.toInt()) {
        parent[i] = i.toLong()
    }
    var count = n.toInt()
    for (e in edges) {
        val time = e[2]
        if (time > t) {
            val u = e[0].toInt()
            val v = e[1].toInt()
            val ru = find(parent, u)
            val rv = find(parent, v)
            if (ru != rv) {
