#include <vector>
#include <algorithm>

using namespace std;

struct UnionFind {
    vector<int> parent;
    UnionFind(int n) : parent(n) {
        for (int i = 0; i < n; ++i) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    void unite(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx != ry) {
            parent[rx] = ry;
        }
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (k == 1) return 0;
    long long max_time = 0;
    for (auto& e : edges) {
        max_time = max(max_time, e[2]);
    }
    long long low = 0, high = max_time;
    long long answer = max_time;
    while (low <= high) {
        long long mid = (low + high) / 2;
        int count = n;
        UnionFind uf(n);
        for (auto& e : edges) {
            long long time = e[2];
            if (time > mid) {
                int u = e[0], v = e[1];
                int ru = uf.find(u);
                int rv = uf.find(v);
                if (ru != rv) {
                    uf.unite(u, v);
                    count--;
                }
            }
        }
        if (count >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
